const body = $input.first().json;

const nome = (body.nome || '').trim();
const whatsapp = (body.whatsapp || '').replace(/\D/g, '');
const area = (body.area || 'Outro').trim();
const mensagem = (body.mensagem || '').trim();

if (!nome || !whatsapp) {
  throw new Error('Nome e WhatsApp são obrigatórios');
}

const whatsappFormatado = whatsapp.startsWith('55') ? whatsapp : `55${whatsapp}`;

return [{ json: { nome, whatsapp, whatsappFormatado, area, mensagem } }];

const lead = $('Code — Normalizar Dados').first().json;
const { nome, whatsapp, area, mensagem } = lead;

const areaContexto = {
  'INSS/Previdência': 'Benefícios previdenciários: aposentadoria por idade, aposentadoria por incapacidade permanente (invalidez), auxílio por incapacidade temporária (auxílio-doença), BPC/LOAS, pensão por morte, salário-maternidade. Carência geral: 12 meses. Doenças graves: carência zero (Art.151 Lei 8213). Recursos: JR e CRPS.',
  'Imposto de Renda': 'Declaração anual de IR, retificação, análise de malha fina, restituição. Obrigatoriedade 2024: rendimentos tributáveis acima de R$30.639,90 ou bens acima de R$800k. Prazo: abril de cada ano.',
  'Precatórios': 'Precatórios são dívidas do poder público reconhecidas judicialmente. Consulta pelo CPF no portal CNJ (cnj.jus.br/precatorios). RPV (Requisição de Pequeno Valor): até 60 salários mínimos. Cessão de precatório: possível com desconto.',
  'Dívidas': 'Negociação extrajudicial com credores. Prescrição de dívidas: 5 anos (regra geral CDC Art.206 §5º I). Verificar juros abusivos, capitalização irregular. Programas: Desenrola Brasil, Serasa Limpa Nome.',
  'Contratos': 'Elaboração e revisão de contratos civis e empresariais. Verificar: cláusulas abusivas (CDC), penalidades, prazos, foro.',
  'Outro': 'Consultoria jurídica geral. Identificar a área correta para encaminhamento.'
};

const contexto = areaContexto[area] || areaContexto['Outro'];
const dataHoje = new Date().toLocaleDateString('pt-BR');

const systemPrompt = `Você é um assistente especializado em direito previdenciário, fiscal e do consumidor brasileiro. Analise os dados do lead e gere um relatório completo em português para a assessora jurídica Jennifer da Oliveira Assessoria Jurídica.

Contexto técnico da área "${area}":
${contexto}

Jennifer pode: gestão administrativa do INSS, recursos administrativos, declaração de IR, negociação de dívidas, consultoria e elaboração de contratos. Ela NÃO pode representar em juízo (sem OAB).

Formate o relatório com as seções exatas abaixo. Use linguagem objetiva e prática.`;

const userPrompt = `Data do cadastro: ${dataHoje}
Nome: ${nome}
WhatsApp: ${whatsapp}
Área de interesse: ${area}
Mensagem do cliente: "${mensagem || 'Não informada'}"

Gere o relatório completo com estas seções:

1. RESUMO DO CASO — 2-3 linhas descrevendo o que o cliente precisa com base na mensagem e na área
2. ANÁLISE DE ELEGIBILIDADE — avalie se o caso tem viabilidade e quais critérios precisam ser confirmados
3. DOCUMENTOS NECESSÁRIOS — lista com os documentos que Jennifer deve solicitar ao cliente
4. PASSO A PASSO — numerado, o que Jennifer deve fazer do passo 1 até a conclusão do caso
5. PRAZO ESTIMADO — tempo médio para resolver esse tipo de caso
6. VALOR SUGERIDO — faixa de preço a cobrar pelo serviço (use como referência: IR R$149, gestão INSS R$300-800, parecer R$500-2000, dívidas R$200-500)
7. PONTOS DE ATENÇÃO — riscos, dúvidas que precisam ser esclarecidas ou limitações (ex: caso precisa de advogado)`;  

return [{ json: { ...lead, systemPrompt, userPrompt } }];

const lead = $('Code — Normalizar Dados').first().json;
const openaiResponse = $input.first().json;

const analise = openaiResponse.choices?.[0]?.message?.content || 'Não foi possível gerar a análise.';
const dataHora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const htmlEmail = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 20px; }
    .container { max-width: 700px; margin: 0 auto; background: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .header { background: #0A1628; color: #ffffff; padding: 24px 32px; }
    .header h1 { margin: 0; font-size: 20px; color: #C9A84C; }
    .header p { margin: 4px 0 0; font-size: 13px; color: #aab4c4; }
    .badge { display: inline-block; background: #C9A84C; color: #0A1628; font-weight: bold; font-size: 12px; padding: 3px 10px; border-radius: 20px; margin-top: 8px; }
    .body { padding: 28px 32px; }
    .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; background: #f8f9fb; border-radius: 6px; padding: 16px; margin-bottom: 24px; }
    .info-item label { font-size: 11px; text-transform: uppercase; color: #888; display: block; margin-bottom: 2px; }
    .info-item span { font-size: 14px; font-weight: bold; color: #0A1628; }
    .analise-box { background: #f8f9fb; border-left: 4px solid #C9A84C; border-radius: 0 6px 6px 0; padding: 20px 24px; white-space: pre-line; font-size: 14px; line-height: 1.7; color: #333; }
    .mensagem-cliente { background: #fffbf0; border: 1px solid #f0e0a0; border-radius: 6px; padding: 14px 18px; font-size: 14px; font-style: italic; color: #555; margin-bottom: 24px; }
    .mensagem-cliente strong { display: block; font-style: normal; color: #0A1628; margin-bottom: 4px; font-size: 12px; text-transform: uppercase; }
    .footer { background: #f0f2f5; padding: 16px 32px; font-size: 12px; color: #888; text-align: center; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📋 Novo Lead — Relatório Completo</h1>
      <p>${dataHora}</p>
      <span class="badge">${lead.area}</span>
    </div>
    <div class="body">
      <div class="info-grid">
        <div class="info-item"><label>Nome</label><span>${lead.nome}</span></div>
        <div class="info-item"><label>WhatsApp</label><span>${lead.whatsapp}</span></div>
        <div class="info-item"><label>Área de Interesse</label><span>${lead.area}</span></div>
        <div class="info-item"><label>Status</label><span>🟢 Novo Lead</span></div>
      </div>
      <div class="mensagem-cliente">
        <strong>Mensagem do cliente:</strong>
        ${lead.mensagem || '<em>Não informada</em>'}
      </div>
      <div class="analise-box">${analise}</div>
    </div>
    <div class="footer">Oliveira Assessoria Jurídica · Gerado automaticamente pelo sistema de atendimento</div>
  </div>
</body>
</html>`;

return [{ json: { ...lead, analise, htmlEmail } }];
